const API_URL = "http://localhost:5000/api";

// Helper para obtener el token y configurar headers
const getAuthHeaders = () => {
    const savedUser = localStorage.getItem('user-session');
    if (savedUser) {
        try {
            const { token } = JSON.parse(savedUser);
            return {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${token}`
            };
        } catch (e) {
            console.error("Error parseando la sesión:", e);
            return { 'Content-Type': 'application/json' };
        }
    }
    return { 'Content-Type': 'application/json' };
};

export const api = {
    // --- AUTENTICACIÓN ---
    login: async (email, password) => {
        const response = await fetch(`${API_URL}/auth/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ correo: email.trim().toLowerCase(), password })
        });
        const data = await response.json();
        if (!response.ok) throw new Error(data.msg || "Error en el login");
        return data; 
    },

    registro: async (datos) => {
        const response = await fetch(`${API_URL}/auth/registro`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(datos)
        });
        const data = await response.json();
        if (!response.ok) throw new Error(data.msg || "Error al registrar");
        return data;
    },

    // --- LOCALES ---
    getLocalesVendedor: async (vendedorId) => {
        const res = await fetch(`${API_URL}/locales/vendedor/${vendedorId}`, {
            headers: getAuthHeaders()
        });
        if (!res.ok) throw new Error("No se pudieron obtener los locales");
        return await res.json();
    },

    crearLocal: async (data) => {
        const res = await fetch(`${API_URL}/locales`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: JSON.stringify(data) 
        });
        if (!res.ok) throw new Error("Error al crear el local");
        return await res.json();
    },

    eliminarLocal: async (id) => {
        const res = await fetch(`${API_URL}/locales/${id}`, {
            method: 'DELETE',
            headers: getAuthHeaders()
        });
        if (!res.ok) throw new Error("No se pudo eliminar el local");
        return await res.json();
    },

    // --- OFERTAS Y PRODUCTOS ---
    publicarLoteOfertas: async (localId, productos) => {
        const res = await fetch(`${API_URL}/ofertas/bulk`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: JSON.stringify({ localId, productos })
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.msg || "Error en la carga masiva");
        return data;
    },

    getTodasLasOfertas: async () => {
        const res = await fetch(`${API_URL}/ofertas`, {
            method: 'GET',
            headers: { 'Content-Type': 'application/json' }
        });
        if (!res.ok) throw new Error("Error al obtener las ofertas");
        return await res.json();
    },

    // --- PEDIDOS ---
    crearPedido: async (pedidoData) => {
        const res = await fetch(`${API_URL}/pedidos`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: JSON.stringify(pedidoData)
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || "Error al crear el pedido");
        return data;
    },

    getPedidosCliente: async (clienteId) => {
        try {
            const res = await fetch(`${API_URL}/pedidos/cliente/${clienteId}`, {
                method: 'GET',
                headers: getAuthHeaders()
            });
            if (!res.ok) {
                const errorData = await res.json();
                throw new Error(errorData.error || "Error al obtener historial");
            }
            return await res.json();
        } catch (error) {
            console.error("Error de conexión con la API:", error);
            throw error; 
        }
    },

    getPedidosVendedor: async (localId) => {
        const res = await fetch(`${API_URL}/pedidos/local/${localId}`, {
            headers: getAuthHeaders()
        });
        if (!res.ok) throw new Error("Error al obtener pedidos del local");
        return await res.json();
    },

    // --- ESTADOS Y CANCELACIÓN ---
    cancelarPedido: async (pedidoId) => {
        const res = await fetch(`${API_URL}/pedidos/${pedidoId}/estado`, {
            method: 'PATCH',
            headers: getAuthHeaders(),
            body: JSON.stringify({ estado: 'cancelado' })
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || "No se pudo cancelar el pedido");
        return data;
    },

    actualizarEstadoPedido: async (pedidoId, nuevoEstado) => {
        const res = await fetch(`${API_URL}/pedidos/${pedidoId}/estado`, {
            method: 'PATCH',
            headers: getAuthHeaders(),
            body: JSON.stringify({ estado: nuevoEstado })
        });
        if (!res.ok) throw new Error("Error al actualizar estado");
        return await res.json();
    }
};
